        // Example mappings for named character references
        full.put("amp", (int) '&');
        full.put("lt", (int) '<');
        full.put("gt", (int) '>');
        full.put("quot", (int) '"');
        full.put("apos", (int) '\'');
        // Add more named references as needed
    }

    static String unescape(String string) {
        if (!string.contains("&")) {
            return string;
        }

        Matcher m = unescapePattern.matcher(string);
        StringBuffer accum = new StringBuffer(string.length());

        while (m.find()) {
            int charval = -1;
            String num = m.group(3);
            if (num != null) {
                try {
                    int base = m.group(2) != null ? 16 : 10; // Determine if it's hex or decimal
                    charval = Integer.parseInt(num, base);
                } catch (NumberFormatException e) {
                    // If parsing fails, charval remains -1
                }
