            // Check if charval is valid
            if (charval != -1 && charval <= 0x10FFFF) { // Ensure it's in the valid Unicode range
                accum.append((char) charval);
            } else {
                accum.append(m.group(0)); // No valid character found, keep the original string
            }
        }
        m.appendTail(accum);
        return accum.toString();
    }
}
